use tracing::{info, warn, error, debug, instrument};
use tracing_subscriber;

#[instrument]
fn process_order(order_id: u64, amount: f64) {
    info!(order_id, amount, "Processing order");

    if amount > 1000.0 {
        warn!(order_id, amount, "Large order detected");
    }

    debug!("Order processing complete");
}

fn main() {
    // Initialize the default subscriber (prints to stdout)
    tracing_subscriber::fmt()
        .with_env_filter("debug")
        .init();

    info!("Application starting");
    process_order(42, 1500.0);
    process_order(43, 50.0);
    error!("Something went wrong!");
}

