use tracing::instrument;

#[instrument(skip(password))]
async fn login(username: &str, password: &str) -> Result<String, String> {
    tracing::info!("Attempting login");
    // password is skipped from span fields for security
    Ok(format!("token_for_{}", username))
}

use tracing::{info, span, Level};

fn handle_request(method: &str, path: &str) {
    let span = span!(Level::INFO, "request", %method, %path);
    let _guard = span.enter();

    info!("Processing request");
    // All events within this scope include method and path
}
